const s=document.querySelector("#style"),n=document.querySelector("#name"),j=document.querySelector("#job"),e=document.querySelector("#email"),f=document.querySelector("#preview"),c=()=>{if(!s.value)return;f.removeAttribute("srcdoc");f.src=`./templates/${encodeURIComponent(s.value)}.html?name=${encodeURIComponent(n.value)}&job=${encodeURIComponent(j.value)}&email=${encodeURIComponent(e.value)}`};s.addEventListener("change",(()=>{c();if(s.value==="chatwoot"){e.disabled=true;e.classList.add("opacity-50")}else{e.disabled=false;e.classList.remove("opacity-50")}}));[n,j,e].forEach(t=>t.addEventListener("keyup",c))